import React from "react";
import Placeholder from "./Placeholder";
import { Link } from "react-router-dom";
import useBurmese from "../../hooks/useBurmese";

export default function Post({ item }) {
  return (
    <Link
      to={`/post/${item?.id ?? "404"}`}
      className={"card mb-3 text-decoration-none"}
      style={{ backgroundColor: "#232" }}
    >
      <div className={"card-body text-light"}>
        <PostTitle title={item?.title} timestamp={item?.timestamp} />
        <PostWriter writer={item?.writer} />
        <PostIntro intro={item?.intro} />
      </div>
    </Link>
  );
}

const PostTitle = ({ title, timestamp }) => {
  const mmTitle = useBurmese(title);

  return Boolean(mmTitle) ? (
    <div className="d-flex flex-row align-items-start">
      <h5 className="card-title flex-grow-1">{mmTitle}</h5>
      <span className="text-small">{timestamp || "July 01, 2022"}</span>
    </div>
  ) : (
    <Placeholder.Title />
  );
};

const PostWriter = ({ writer, className }) => {
  const mmWriter = useBurmese(writer);

  return Boolean(mmWriter) ? (
    <div className={"fst-italic " + className}>
      {mmWriter || "credit to original writer"}
    </div>
  ) : (
    <Placeholder.Title col={4} />
  );
};

const PostImage = ({ url }) => {
  const [isLoaded, setLoaded] = React.useState(false);

  const loaded = React.useCallback(() => setLoaded(true), []);

  return (
    <div className="py-3">
      {!isLoaded && <Placeholder.Image />}
      <img
        className={isLoaded ? "" : "d-none "}
        onLoad={loaded}
        src={url}
        alt={"poster"}
        width={"100%"}
        height={"auto"}
      />
    </div>
  );
};

const PostAudio = ({ url }) => {
  const changeRate = React.useCallback(() => {
    document.getElementById("audio").playbackRate = 1.25;
  }, []);

  return (
    <audio
      className="w-100 position-fixed bottom-0 start-0 end-0"
      style={{ height: "2.5rem" }}
      controls={true}
      muted={false}
      autoPlay={false}
      controlsList={"nodownload"}
      id={"audio"}
      src={url}
      onCanPlay={changeRate}
    >
      <span>Your browser does not support this audio format.</span>
    </audio>
  );
};

const PostIntro = ({ intro }) => {
  const mmIntro = useBurmese(intro);

  return Boolean(mmIntro) ? (
    <p className="card-text">{mmIntro}</p>
  ) : (
    <Placeholder.Paragraph />
  );
};

const PostStory = ({ story }) => {
  const mmStory = useBurmese(story);

  return mmStory ? (
    <p className="card-text" style={{ whiteSpace: "pre-wrap" }}>
      {mmStory}
    </p>
  ) : (
    <div>
      <Placeholder.Paragraph />
      <Placeholder.Paragraph />
      <Placeholder.Paragraph />
    </div>
  );
};

Post.Title = PostTitle;
Post.Writer = PostWriter;
Post.Intro = PostIntro;
Post.Story = PostStory;
Post.Image = PostImage;
Post.Audio = PostAudio;
